import { writable } from 'svelte/store'

/**
 * 探索模式反馈 Store
 * 用于在探索模式中显示操作结果
 */
function createExploreFeedback() {
    const { subscribe, set, update } = writable(null)

    return {
        subscribe,
        
        // 设置反馈信息
        setFeedback(message, type = 'info') {
            set({ message, type })
        },
        
        // 清除反馈
        clear() {
            set(null)
        },
        
        // 2秒后自动清除
        setTimedFeedback(message, type = 'info', duration = 2000) {
            set({ message, type })
            setTimeout(() => set(null), duration)
        }
    }
}

export const exploreFeedback = createExploreFeedback()
